namespace sv_39aee59170654e78b565c98ca783938b.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(DateTimeOffset Timestamp, string Description);

using sv_39aee59170654e78b565c98ca783938b.Client.Services;

namespace sv_39aee59170654e78b565c98ca783938b.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), "Package picked up"),
                new(new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility"),
                new(new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), "In transit to destination hub"),
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Austin, TX",
            new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero), "Package picked up"),
                new(new DateTimeOffset(2026, 5, 19, 11, 0, 0, TimeSpan.Zero), "Arrived at regional hub"),
                new(new DateTimeOffset(2026, 5, 20, 7, 45, 0, TimeSpan.Zero), "Out for delivery"),
                new(new DateTimeOffset(2026, 5, 20, 14, 20, 0, TimeSpan.Zero), "Delivered"),
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero), "Order received, preparing shipment"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
            return shipment;

        throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
    }
}

using System.Net.Http.Json;

namespace sv_39aee59170654e78b565c98ca783938b.Client.Services;

public class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public HttpShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received null response from server.");
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_39aee59170654e78b565c98ca783938b.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in _shipment.Updates)
        {
            <li><strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description</li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — nothing to do
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogError("Request timed out for shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException)
        {
            Logger.LogError("Request timed out for shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException)
        {
            Logger.LogWarning("Shipment {TrackingNumber} not found", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

